def _vendor_key(label):
    """Return matching vendor key for a node label, or None."""
    label_lower = label.lower().replace("-", "").replace("_", "").replace(" ", "").replace(".", "")
    for key in VENDOR_ICON_DATA:
        if key in label_lower:
            return key
    return None


